@* Vertical sidebar navigation for settings sections *@

<nav class="nav nav-pills flex-column settings-sidebar">
    @foreach (var section in Sections)
    {
        <button class="nav-link text-start @(section == ActiveSection ? "active" : "")"
                @onclick="() => OnSectionChanged.InvokeAsync(section)">
            <span class="me-2">@GetIcon(section)</span> @section
        </button>
    }
</nav>

@code {
    [Parameter, EditorRequired] public string ActiveSection { get; set; } = "";
    [Parameter, EditorRequired] public EventCallback<string> OnSectionChanged { get; set; }

    private static readonly string[] Sections = { "Profile", "Notifications", "Security", "Appearance" };

    private static string GetIcon(string section) => section switch
    {
        "Profile" => "👤",
        "Notifications" => "🔔",
        "Security" => "🔒",
        "Appearance" => "🎨",
        _ => "⚙️"
    };
}

@using sv_ad922d09ae8d4dca93edc57b4039ad5f.Services
@inject ISettingsService SettingsService

<div class="settings-section">
    <h4 class="mb-4">Profile Settings</h4>

    @if (_profile is null)
    {
        <p class="text-muted">Loading…</p>
        return;
    }

    @if (!string.IsNullOrEmpty(_message))
    {
        <div class="alert @(_isError ? "alert-danger" : "alert-success") alert-dismissible fade show" role="alert">
            @_message
            <button type="button" class="btn-close" @onclick="() => _message = null"></button>
        </div>
    }

    <div class="row">
        <div class="col-md-8">
            <div class="mb-3">
                <label class="form-label">Display Name</label>
                <input type="text" class="form-control" @bind="_displayName" />
            </div>
            <div class="mb-3">
                <label class="form-label">Email</label>
                <input type="email" class="form-control" @bind="_email" />
            </div>
            <div class="mb-3">
                <label class="form-label">Bio</label>
                <textarea class="form-control" rows="4" @bind="_bio"></textarea>
            </div>
        </div>
        <div class="col-md-4 text-center">
            <div class="mb-3">
                <label class="form-label">Avatar Preview</label>
                <div class="border rounded p-2 mb-2">
                    @if (!string.IsNullOrWhiteSpace(_avatarUrl))
                    {
                        <img src="@_avatarUrl" alt="Avatar" class="rounded-circle img-fluid" style="max-width:120px;max-height:120px;" />
                    }
                    else
                    {
                        <div class="bg-secondary rounded-circle d-inline-flex align-items-center justify-content-center" style="width:120px;height:120px;">
                            <span class="text-white fs-1">👤</span>
                        </div>
                    }
                </div>
                <small class="text-muted text-break">@_avatarUrl</small>
            </div>
        </div>
    </div>

    <div class="d-flex gap-2">
        <button class="btn btn-primary" @onclick="SaveAsync" disabled="@_saving">
            @if (_saving) { <span class="spinner-border spinner-border-sm me-1"></span> }
            Save Changes
        </button>
        <button class="btn btn-outline-secondary" @onclick="Discard" disabled="@_saving">
            Discard Changes
        </button>
    </div>
</div>

@code {
    private UserProfile? _profile;
    private string _displayName = "";
    private string _email = "";
    private string _bio = "";
    private string _avatarUrl = "";
    private bool _saving;
    private string? _message;
    private bool _isError;

    protected override async Task OnInitializedAsync()
    {
        await LoadAsync();
    }

    private async Task LoadAsync()
    {
        _profile = await SettingsService.GetProfileAsync();
        PopulateFields(_profile);
    }

    private void PopulateFields(UserProfile p)
    {
        _displayName = p.DisplayName;
        _email = p.Email;
        _bio = p.Bio;
        _avatarUrl = p.AvatarUrl;
    }

    private async Task SaveAsync()
    {
        _saving = true;
        _message = null;
        try
        {
            var updated = new UserProfile(_displayName, _email, _avatarUrl, _bio);
            await SettingsService.SaveProfileAsync(updated);
            _profile = updated;
            _message = "Profile saved successfully!";
            _isError = false;
        }
        catch
        {
            _message = "Failed to save profile.";
            _isError = true;
        }
        finally
        {
            _saving = false;
        }
    }

    private void Discard()
    {
        if (_profile is not null)
        {
            PopulateFields(_profile);
        }
        _message = null;
    }
}

@using sv_ad922d09ae8d4dca93edc57b4039ad5f.Services
@inject ISettingsService SettingsService

<div class="settings-section">
    <h4 class="mb-4">Notification Preferences</h4>

    @if (_prefs is null)
    {
        <p class="text-muted">Loading…</p>
        return;
    }

    @if (!string.IsNullOrEmpty(_message))
    {
        <div class="alert alert-success alert-dismissible fade show" role="alert">
            @_message
            <button type="button" class="btn-close" @onclick="() => _message = null"></button>
        </div>
    }

    <div class="mb-4">
        <div class="form-check form-switch mb-3">
            <input class="form-check-input" type="checkbox" id="emailNotif" @bind="_emailNotifications" />
            <label class="form-check-label" for="emailNotif">Email Notifications</label>
        </div>
        <div class="form-check form-switch mb-3">
            <input class="form-check-input" type="checkbox" id="pushNotif" @bind="_pushNotifications" />
            <label class="form-check-label" for="pushNotif">Push Notifications</label>
        </div>
        <div class="form-check form-switch mb-3">
            <input class="form-check-input" type="checkbox" id="weeklyDigest" @bind="_weeklyDigest" />
            <label class="form-check-label" for="weeklyDigest">Weekly Digest</label>
        </div>
    </div>

    <h5 class="mb-3">Muted Channels</h5>
    <div class="mb-4">
        @foreach (var channel in _allChannels)
        {
            var isMuted = _mutedChannels.Contains(channel);
            <div class="form-check mb-2">
                <input class="form-check-input" type="checkbox" id="@($"ch-{channel}")"
                       checked="@isMuted"
                       @onchange="e => ToggleChannel(channel, (bool)(e.Value ?? false))" />
                <label class="form-check-label" for="@($"ch-{channel}")">@channel</label>
            </div>
        }
    </div>

    <button class="btn btn-primary" @onclick="SaveAsync" disabled="@_saving">
        @if (_saving) { <span class="spinner-border spinner-border-sm me-1"></span> }
        Save Preferences
    </button>
</div>

@code {
    private NotificationPrefs? _prefs;
    private bool _emailNotifications;
    private bool _pushNotifications;
    private bool _weeklyDigest;
    private HashSet<string> _mutedChannels = new();
    private bool _saving;
    private string? _message;

    private static readonly string[] _allChannels = { "general", "engineering", "marketing", "support", "announcements" };

    protected override async Task OnInitializedAsync()
    {
        _prefs = await SettingsService.GetNotificationPrefsAsync();
        _emailNotifications = _prefs.EmailNotifications;
        _pushNotifications = _prefs.PushNotifications;
        _weeklyDigest = _prefs.WeeklyDigest;
        _mutedChannels = new HashSet<string>(_prefs.MutedChannels);
    }

    private void ToggleChannel(string channel, bool muted)
    {
        if (muted)
            _mutedChannels.Add(channel);
        else
            _mutedChannels.Remove(channel);
    }

    private async Task SaveAsync()
    {
        _saving = true;
        _message = null;
        try
        {
            var updated = new NotificationPrefs(_emailNotifications, _pushNotifications, _weeklyDigest, _mutedChannels.ToList());
            await SettingsService.SaveNotificationPrefsAsync(updated);
            _prefs = updated;
            _message = "Preferences saved!";
        }
        finally
        {
            _saving = false;
        }
    }
}

@* Expandable panel for changing password *@

<div class="card mb-4">
    <div class="card-header d-flex justify-content-between align-items-center"
         style="cursor:pointer" @onclick="() => _expanded = !_expanded">
        <span>🔑 Change Password</span>
        <span>@(_expanded ? "▲" : "▼")</span>
    </div>
    @if (_expanded)
    {
        <div class="card-body">
            @if (!string.IsNullOrEmpty(_message))
            {
                <div class="alert @(_isError ? "alert-danger" : "alert-success") alert-dismissible fade show">
                    @_message
                    <button type="button" class="btn-close" @onclick="() => _message = null"></button>
                </div>
            }
            <div class="mb-3">
                <label class="form-label">Current Password</label>
                <input type="password" class="form-control" @bind="_currentPassword" />
            </div>
            <div class="mb-3">
                <label class="form-label">New Password</label>
                <input type="password" class="form-control" @bind="_newPassword" />
            </div>
            <div class="mb-3">
                <label class="form-label">Confirm New Password</label>
                <input type="password" class="form-control" @bind="_confirmPassword" />
            </div>
            <button class="btn btn-warning" @onclick="UpdatePasswordAsync" disabled="@_saving">
                @if (_saving) { <span class="spinner-border spinner-border-sm me-1"></span> }
                Update Password
            </button>
        </div>
    }
</div>

@code {
    [Parameter, EditorRequired] public EventCallback<(string Current, string New)> OnChangePassword { get; set; }

    private bool _expanded;
    private string _currentPassword = "";
    private string _newPassword = "";
    private string _confirmPassword = "";
    private bool _saving;
    private string? _message;
    private bool _isError;

    private async Task UpdatePasswordAsync()
    {
        _message = null;

        if (string.IsNullOrWhiteSpace(_currentPassword) || string.IsNullOrWhiteSpace(_newPassword))
        {
            _message = "Please fill in all password fields.";
            _isError = true;
            return;
        }

        if (_newPassword != _confirmPassword)
        {
            _message = "New passwords do not match.";
            _isError = true;
            return;
        }

        _saving = true;
        try
        {
            await OnChangePassword.InvokeAsync((_currentPassword, _newPassword));
            _message = "Password updated successfully!";
            _isError = false;
            _currentPassword = "";
            _newPassword = "";
            _confirmPassword = "";
        }
        catch
        {
            _message = "Failed to update password.";
            _isError = true;
        }
        finally
        {
            _saving = false;
        }
    }
}

@* Modal confirmation dialog before revoking a session *@

@if (Visible)
{
    <div class="modal fade show d-block" tabindex="-1" style="background-color:rgba(0,0,0,.5)">
        <div class="modal-dialog modal-dialog-centered">
            <div class="modal-content">
                <div class="modal-header">
                    <h5 class="modal-title">Revoke Session</h5>
                    <button type="button" class="btn-close" @onclick="Cancel"></button>
                </div>
                <div class="modal-body">
                    @if (Session is not null)
                    {
                        <p>Are you sure you want to revoke the session on <strong>@Session.Device</strong> from <strong>@Session.Location</strong>?</p>
                        <p class="text-muted small">This will immediately sign out that device.</p>
                    }
                </div>
                <div class="modal-footer">
                    <button class="btn btn-secondary" @onclick="Cancel">Cancel</button>
                    <button class="btn btn-danger" @onclick="Confirm">Revoke</button>
                </div>
            </div>
        </div>
    </div>
}

@code {
    [Parameter] public bool Visible { get; set; }
    [Parameter] public ActiveSession? Session { get; set; }
    [Parameter, EditorRequired] public EventCallback OnConfirmed { get; set; }
    [Parameter, EditorRequired] public EventCallback OnCancelled { get; set; }

    private async Task Confirm() => await OnConfirmed.InvokeAsync();
    private async Task Cancel() => await OnCancelled.InvokeAsync();
}

@using sv_ad922d09ae8d4dca93edc57b4039ad5f.Services

@using sv_ad922d09ae8d4dca93edc57b4039ad5f.Services
@inject ISettingsService SettingsService

<div class="settings-section">
    <h4 class="mb-4">Security</h4>

    @if (_settings is null)
    {
        <p class="text-muted">Loading…</p>
        return;
    }

    <ChangePasswordPanel OnChangePassword="HandleChangePasswordAsync" />

    <div class="card mb-4">
        <div class="card-body d-flex justify-content-between align-items-center">
            <div>
                <h6 class="mb-1">Two-Factor Authentication</h6>
                <span class="badge @(_twoFactorEnabled ? "bg-success" : "bg-secondary")">
                    @(_twoFactorEnabled ? "Enabled" : "Disabled")
                </span>
                @if (_settings.LastPasswordChange.HasValue)
                {
                    <small class="text-muted ms-3">Last password change: @_settings.LastPasswordChange.Value.ToString("MMM dd, yyyy")</small>
                }
            </div>
            <div class="form-check form-switch">
                <input class="form-check-input" type="checkbox" @bind="_twoFactorEnabled" />
            </div>
        </div>
    </div>

    <h5 class="mb-3">Active Sessions</h5>
    <div class="table-responsive">
        <table class="table table-hover">
            <thead>
                <tr>
                    <th>Device</th>
                    <th>Location</th>
                    <th>Last Active</th>
                    <th></th>
                </tr>
            </thead>
            <tbody>
                @foreach (var session in _sessions)
                {
                    var isCurrent = session == _sessions.FirstOrDefault();
                    <tr>
                        <td>
                            @session.Device
                            @if (isCurrent)
                            {
                                <span class="badge bg-primary ms-1">Current</span>
                            }
                        </td>
                        <td>@session.Location</td>
                        <td>@FormatLastActive(session.LastActive)</td>
                        <td>
                            @if (!isCurrent)
                            {
                                <button class="btn btn-sm btn-outline-danger"
                                        @onclick="() => ShowRevokeDialog(session)">
                                    Revoke
                                </button>
                            }
                        </td>
                    </tr>
                }
            </tbody>
        </table>
    </div>

    <RevokeSessionDialog Visible="_revokeDialogVisible"
                         Session="_sessionToRevoke"
                         OnConfirmed="ConfirmRevokeAsync"
                         OnCancelled="CancelRevoke" />
</div>

@code {
    private SecuritySettings? _settings;
    private List<ActiveSession> _sessions = new();
    private bool _twoFactorEnabled;
    private bool _revokeDialogVisible;
    private ActiveSession? _sessionToRevoke;

    protected override async Task OnInitializedAsync()
    {
        await LoadAsync();
    }

    private async Task LoadAsync()
    {
        _settings = await SettingsService.GetSecuritySettingsAsync();
        _sessions = _settings.Sessions;
        _twoFactorEnabled = _settings.TwoFactorEnabled;
    }

    private async Task HandleChangePasswordAsync((string Current, string New) args)
    {
        await SettingsService.ChangePasswordAsync(args.Current, args.New);
        await LoadAsync();
    }

    private void ShowRevokeDialog(ActiveSession session)
    {
        _sessionToRevoke = session;
        _revokeDialogVisible = true;
    }

    private async Task ConfirmRevokeAsync()
    {
        if (_sessionToRevoke is not null)
        {
            await SettingsService.RevokeSessionAsync(_sessionToRevoke.Id);
            await LoadAsync();
        }
        _revokeDialogVisible = false;
        _sessionToRevoke = null;
    }

    private void CancelRevoke()
    {
        _revokeDialogVisible = false;
        _sessionToRevoke = null;
    }

    private static string FormatLastActive(DateTime dt)
    {
        var diff = DateTime.UtcNow - dt;
        if (diff.TotalMinutes < 1) return "Just now";
        if (diff.TotalMinutes < 60) return $"{(int)diff.TotalMinutes}m ago";
        if (diff.TotalHours < 24) return $"{(int)diff.TotalHours}h ago";
        return $"{(int)diff.TotalDays}d ago";
    }
}

