@* Modal confirmation dialog before revoking a session *@

@if (Visible)
{
    <div class="modal fade show d-block" tabindex="-1" style="background-color:rgba(0,0,0,.5)">
        <div class="modal-dialog modal-dialog-centered">
            <div class="modal-content">
                <div class="modal-header">
                    <h5 class="modal-title">Revoke Session</h5>
                    <button type="button" class="btn-close" @onclick="Cancel"></button>
                </div>
                <div class="modal-body">
                    @if (Session is not null)
                    {
                        <p>Are you sure you want to revoke the session on <strong>@Session.Device</strong> from <strong>@Session.Location</strong>?</p>
                        <p class="text-muted small">This will immediately sign out that device.</p>
                    }
                </div>
                <div class="modal-footer">
                    <button class="btn btn-secondary" @onclick="Cancel">Cancel</button>
                    <button class="btn btn-danger" @onclick="Confirm">Revoke</button>
                </div>
            </div>
        </div>
    </div>
}

@code {
    [Parameter] public bool Visible { get; set; }
    [Parameter] public ActiveSession? Session { get; set; }
    [Parameter, EditorRequired] public EventCallback OnConfirmed { get; set; }
    [Parameter, EditorRequired] public EventCallback OnCancelled { get; set; }

    private async Task Confirm() => await OnConfirmed.InvokeAsync();
    private async Task Cancel() => await OnCancelled.InvokeAsync();
}

@using sv_ad922d09ae8d4dca93edc57b4039ad5f.Services

@using sv_ad922d09ae8d4dca93edc57b4039ad5f.Services
@inject ISettingsService SettingsService

<div class="settings-section">
    <h4 class="mb-4">Security</h4>

    @if (_settings is null)
    {
        <p class="text-muted">Loading…</p>
        return;
    }

    <ChangePasswordPanel OnChangePassword="HandleChangePasswordAsync" />

    <div class="card mb-4">
        <div class="card-body d-flex justify-content-between align-items-center">
            <div>
                <h6 class="mb-1">Two-Factor Authentication</h6>
                <span class="badge @(_twoFactorEnabled ? "bg-success" : "bg-secondary")">
                    @(_twoFactorEnabled ? "Enabled" : "Disabled")
                </span>
                @if (_settings.LastPasswordChange.HasValue)
                {
                    <small class="text-muted ms-3">Last password change: @_settings.LastPasswordChange.Value.ToString("MMM dd, yyyy")</small>
                }
            </div>
            <div class="form-check form-switch">
                <input class="form-check-input" type="checkbox" @bind="_twoFactorEnabled" />
            </div>
        </div>
    </div>

    <h5 class="mb-3">Active Sessions</h5>
    <div class="table-responsive">
        <table class="table table-hover">
            <thead>
                <tr>
                    <th>Device</th>
                    <th>Location</th>
                    <th>Last Active</th>
                    <th></th>
                </tr>
            </thead>
            <tbody>
                @foreach (var session in _sessions)
                {
                    var isCurrent = session == _sessions.FirstOrDefault();
                    <tr>
                        <td>
                            @session.Device
                            @if (isCurrent)
                            {
                                <span class="badge bg-primary ms-1">Current</span>
                            }
                        </td>
                        <td>@session.Location</td>
                        <td>@FormatLastActive(session.LastActive)</td>
                        <td>
                            @if (!isCurrent)
                            {
                                <button class="btn btn-sm btn-outline-danger"
                                        @onclick="() => ShowRevokeDialog(session)">
                                    Revoke
                                </button>
                            }
                        </td>
                    </tr>
                }
            </tbody>
        </table>
    </div>

    <RevokeSessionDialog Visible="_revokeDialogVisible"
                         Session="_sessionToRevoke"
                         OnConfirmed="ConfirmRevokeAsync"
                         OnCancelled="CancelRevoke" />
</div>

@code {
    private SecuritySettings? _settings;
    private List<ActiveSession> _sessions = new();
    private bool _twoFactorEnabled;
    private bool _revokeDialogVisible;
    private ActiveSession? _sessionToRevoke;

    protected override async Task OnInitializedAsync()
    {
        await LoadAsync();
    }

    private async Task LoadAsync()
    {
        _settings = await SettingsService.GetSecuritySettingsAsync();
        _sessions = _settings.Sessions;
        _twoFactorEnabled = _settings.TwoFactorEnabled;
    }

    private async Task HandleChangePasswordAsync((string Current, string New) args)
    {
        await SettingsService.ChangePasswordAsync(args.Current, args.New);
        await LoadAsync();
    }

    private void ShowRevokeDialog(ActiveSession session)
    {
        _sessionToRevoke = session;
        _revokeDialogVisible = true;
    }

    private async Task ConfirmRevokeAsync()
    {
        if (_sessionToRevoke is not null)
        {
            await SettingsService.RevokeSessionAsync(_sessionToRevoke.Id);
            await LoadAsync();
        }
        _revokeDialogVisible = false;
        _sessionToRevoke = null;
    }

    private void CancelRevoke()
    {
        _revokeDialogVisible = false;
        _sessionToRevoke = null;
    }

    private static string FormatLastActive(DateTime dt)
    {
        var diff = DateTime.UtcNow - dt;
        if (diff.TotalMinutes < 1) return "Just now";
        if (diff.TotalMinutes < 60) return $"{(int)diff.TotalMinutes}m ago";
        if (diff.TotalHours < 24) return $"{(int)diff.TotalHours}h ago";
        return $"{(int)diff.TotalDays}d ago";
    }
}

