@using sv_ad922d09ae8d4dca93edc57b4039ad5f.Services
@inject ISettingsService SettingsService

<div class="settings-section">
    <h4 class="mb-4">Appearance</h4>

    @if (_settings is null)
    {
        <p class="text-muted">Loading…</p>
        return;
    }

    @if (!string.IsNullOrEmpty(_message))
    {
        <div class="alert alert-success alert-dismissible fade show">
            @_message
            <button type="button" class="btn-close" @onclick="() => _message = null"></button>
        </div>
    }

    <div class="row">
        <div class="col-md-6">
            <div class="mb-4">
                <h6>Theme</h6>
                @foreach (var theme in new[] { "Light", "Dark", "System" })
                {
                    <div class="form-check">
                        <input class="form-check-input" type="radio" name="theme" id="@($"theme-{theme}")"
                               value="@theme" checked="@(_theme == theme)"
                               @onchange="() => _theme = theme" />
                        <label class="form-check-label" for="@($"theme-{theme}")">@theme</label>
                    </div>
                }
            </div>

            <div class="mb-4">
                <h6>Font Size</h6>
                @foreach (var size in new[] { "Small", "Medium", "Large" })
                {
                    <div class="form-check">
                        <input class="form-check-input" type="radio" name="fontSize" id="@($"fs-{size}")"
                               value="@size" checked="@(_fontSize == size)"
                               @onchange="() => _fontSize = size" />
                        <label class="form-check-label" for="@($"fs-{size}")">@size</label>
                    </div>
                }
            </div>

            <div class="mb-4">
                <h6>Language</h6>
                <select class="form-select" @bind="_language">
                    <option value="English">English</option>
                    <option value="Spanish">Spanish</option>
                    <option value="French">French</option>
                    <option value="German">German</option>
                    <option value="Japanese">Japanese</option>
                </select>
            </div>

            <div class="mb-4">
                <div class="form-check form-switch">
                    <input class="form-check-input" type="checkbox" id="compactMode" @bind="_compactMode" />
                    <label class="form-check-label" for="compactMode">Compact Mode</label>
                </div>
            </div>

            <button class="btn btn-primary" @onclick="SaveAsync" disabled="@_saving">
                @if (_saving) { <span class="spinner-border spinner-border-sm me-1"></span> }
                Save
            </button>
        </div>

        <div class="col-md-6">
            <h6>Live Preview</h6>
            <div class="border rounded p-3 @PreviewBackgroundClass" style="@PreviewFontStyle; min-height:200px;">
                <div class="@PreviewTextClass mb-2" style="font-weight:600;">
                    Sample Heading
                </div>
                <p class="@PreviewTextClass @(_compactMode ? "mb-1" : "mb-3")" style="@PreviewFontStyle">
                    This is a preview of how your content will look with the selected appearance settings.
                </p>
                <div class="d-flex gap-2 @(_compactMode ? "mb-1" : "mb-2")">
                    <span class="badge bg-primary">Tag 1</span>
                    <span class="badge bg-secondary">Tag 2</span>
                </div>
                <button class="btn btn-sm @PreviewButtonClass">Example Button</button>
                <div class="mt-2">
                    <small class="@PreviewMutedClass">Language: @_language</small>
                </div>
            </div>
        </div>
    </div>
</div>

@code {
    private AppearanceSettings? _settings;
    private string _theme = "Light";
    private string _fontSize = "Medium";
    private string _language = "English";
    private bool _compactMode;
    private bool _saving;
    private string? _message;

    protected override async Task OnInitializedAsync()
    {
        _settings = await SettingsService.GetAppearanceAsync();
        _theme = _settings.Theme;
        _fontSize = _settings.FontSize;
        _language = _settings.Language;
        _compactMode = _settings.CompactMode;
    }

    private async Task SaveAsync()
    {
        _saving = true;
        _message = null;
        try
        {
            var updated = new AppearanceSettings(_theme, _fontSize, _language, _compactMode);
            await SettingsService.SaveAppearanceAsync(updated);
            _settings = updated;
            _message = "Appearance saved!";
        }
        finally
        {
            _saving = false;
        }
    }

    private string PreviewFontStyle => _fontSize switch
    {
        "Small" => "font-size:0.85rem;",
        "Large" => "font-size:1.25rem;",
        _ => "font-size:1rem;"
    };

    private string PreviewBackgroundClass => _theme switch
    {
        "Dark" => "bg-dark",
        _ => "bg-light"
    };

    private string PreviewTextClass => _theme switch
    {
        "Dark" => "text-light",
        _ => "text-dark"
    };

    private string PreviewButtonClass => _theme switch
    {
        "Dark" => "btn-outline-light",
        _ => "btn-outline-dark"
    };

    private string PreviewMutedClass => _theme switch
    {
        "Dark" => "text-light opacity-50",
        _ => "text-muted"
    };
}

